patterns.codeBlock:
let value = original.clone();
use_value(value);
// `original` is still valid here

{
    let first = &mut data;
    first.push(1);
} // first borrow ends here
let second = &mut data;

let result = {
    let mutref = &mut data;
    mutref.modify();
    mutref.get_result()
};
println!("{}", data); // immutable borrow is fine now

let reference = &data;
println!("{}", reference);
// reference is no longer used
drop(reference);
let moved = data; // now safe to move

// Instead of:
// let val = *some_ref;
// Use:
let val = some_ref.clone();

#[derive(Debug, Clone, PartialEq)]
struct MyType {
    // fields
}

let values: Vec<i32> = vec![];
// or
let values = Vec::<i32>::new();

use crate::module::{typeName};
// or
use some_crate::{typeName};

use std::ops::Add;

impl Add for MyType {
    type Output = Self;
    fn add(self, other: Self) -> Self {
        // implementation
    }
}

// In Cargo.toml:
[dependencies]
some_crate = "1.0"

// In your code:
use some_crate::module::Item;

fn longest<'a>(x: &'a str, y: &'a str) -> &'a str {
    if x.len() > y.len() { x } else { y }
}

fn process<'a>(input: &'a str) -> &'a str {
    // ...
}

impl MyTrait for MyType {
    fn required_method(&self) {
        // implementation
    }
}

let instance = MyStruct {
    field1: value1,
    field2: value2,
    ..Default::default()
};

// Wrong: fn process(input: Some) { }
// Right:
fn process(input: Option<String>) {
    if let Some(val) = input { /* ... */ }
}

// SAFETY: the pointer is guaranteed to be valid and aligned
unsafe {
    dangerous_function();
}

use once_cell::sync::Lazy;

static VALUE: Lazy<MyType> = Lazy::new(|| {
    compute_value()
});

// Instead of:
// value.unwrap()
// Use:
match value {
    Some(v) => v,
    None => return Err("value was None".into()),
}

// Use the ? operator for propagation:
let value = some_option.ok_or("missing value")?;

// Or provide a default:
let value = some_option.unwrap_or(default_value);

// Checked (returns None on overflow):
let result = a.checked_add(b);

// Saturating (clamps to max/min):
let result = a.saturating_add(b);

// Wrapping (wraps around):
let result = a.wrapping_add(b);

// Safe access:
if let Some(value) = collection.get(index) {
    // use value
}

// Or with a default:
let value = collection.get(index).unwrap_or(&default);

// Convert recursion to iteration:
fn factorial(n: u64) -> u64 {
    (1..=n).product()
}

// Or increase stack size:
std::thread::Builder::new()
    .stack_size(8 * 1024 * 1024)
    .spawn(|| { /* work */ })
    .unwrap();

